SELECT id, name, email, role, created_at
FROM users
WHERE active = true;

-- Parameterized but still vulnerable to wildcard abuse:
SELECT * FROM products
WHERE name LIKE '%' || $1 || '%';
-- If $1 = '%', this becomes LIKE '%%%' = every row

-- Safe version: escape wildcards in the input
SELECT * FROM products
WHERE name LIKE '%' || replace(
  replace($1, '%', '\%'),
  '_', '\_'
) || '%';

-- These are NOT equivalent:
SELECT * FROM users WHERE status = 'active';
SELECT * FROM users WHERE NOT (status != 'active');
-- Second query ALSO excludes NULL status!
-- Because: NULL != 'active' = NULL, NOT NULL = NULL

-- To get NULLs too:
SELECT * FROM users
WHERE status = 'active' OR status IS NULL;

